import React, { useState, useEffect, useRef } from 'react';
import { 
  Send, Mic, Image as ImageIcon, Terminal, X, 
  Activity, ChevronLeft, LayoutGrid, BrainCircuit, 
  Globe, Zap, ScanEye, Wand2, Paperclip, Shield, Skull, Cpu, 
  Volume2, VolumeX, Trash2, Radio, StopCircle, Settings2, ChevronDown,
  AlertTriangle, CheckCircle2, Flame, Search, ScanLine, Code2, Copy, Check, Download, StopCircle as StopIcon
} from 'lucide-react';
import { Message, Role, Attachment, GenerationMode, AstraMode, VoiceSettings, GroundingMetadata } from '../types';
import { 
  sendMessageToGemini, 
  initializeChat, 
  generateEditedImage, 
  runAstraDetection,
  speakText,
  AstraLiveSession
} from '../services/geminiService';
import { 
  INITIAL_GREETING_SHIELD, 
  INITIAL_GREETING_SKULL, 
  INITIAL_GREETING_ROOT 
} from '../constants';
import ReactMarkdown from 'react-markdown';
import { Logo } from './Logo';
import { motion, AnimatePresence } from 'framer-motion';
import { Typewriter } from './Typewriter';
import { AstraScanner } from './AstraScanner';
import { MatrixRain } from './MatrixRain';
import { VoiceVisualizer } from './VoiceVisualizer';
import { Tooltip } from './Tooltip';
import { Content } from '@google/genai';

interface ChatInterfaceProps {
  onBack: () => void;
}

const DEFAULT_VOICE_SETTINGS: VoiceSettings = {
    shield: { pitch: 1.0, rate: 1.0, voiceURI: '' },
    skull: { pitch: 0.1, rate: 0.6, voiceURI: '' },
    root: { pitch: 0.4, rate: 1.1, voiceURI: '' }
};

const detectNewsIntent = (text: string): boolean => {
    const keywords = ["news", "latest", "recent", "update", "current", "today", "now", "weather", "stock", "price", "match"];
    const lower = text.toLowerCase();
    return keywords.some(k => lower.includes(k));
};

const getHistoryForGemini = (msgs: Message[]): Content[] => {
    return msgs
     .filter((m: Message) => m.id !== 'init' && !m.text.startsWith('>> IMAGE_GENERATED')) 
     .map((m: Message) => ({ 
         role: m.role === Role.USER ? 'user' : 'model', 
         parts: [{ text: m.text }] 
     }));
};

const ForensicResultDisplay = ({ text }: { text: string }) => {
  const anomalyMatch = text.match(/\[ANOMALIES_DETECTED\]([\s\S]*?)\[FORENSIC_REPORT\]/);
  const reportMatch = text.match(/\[FORENSIC_REPORT\]([\s\S]*?)\[CONCLUSION\]/);
  const conclusionMatch = text.match(/\[CONCLUSION\]([\s\S]*)/);
  const anomalies = anomalyMatch ? anomalyMatch[1].trim().split('\n').map(l => l.replace(/^-\s*/, '').trim()).filter(Boolean) : [];
  const report = reportMatch ? reportMatch[1].trim() : "";
  const conclusion = conclusionMatch ? conclusionMatch[1].trim() : "";

  if (!anomalyMatch && !reportMatch && !conclusionMatch) {
      return <div className="text-xs font-mono text-astra-blue animate-pulse">>> DECRYPTING_FORENSIC_DATA...</div>;
  }

  const isDanger = conclusion.toLowerCase().includes('ai_generated') || conclusion.toLowerCase().includes('fake');

  return (
    <div className="space-y-4 w-full mt-2">
        <div className="space-y-2">
            <div className="text-[10px] font-orbitron text-astra-saffron tracking-widest flex items-center gap-2 border-b border-astra-saffron/20 pb-1">
                <AlertTriangle size={12} /> DETECTED_ANOMALIES
            </div>
            <div className="grid grid-cols-1 gap-2">
                {anomalies.map((anomaly, idx) => (
                    <div key={idx} className="bg-red-500/10 border-l-2 border-red-500 p-2 text-xs font-mono text-red-200 flex items-start gap-2 rounded-r">
                        <ScanLine size={14} className="shrink-0 text-red-500 mt-0.5" />
                        <span>{anomaly}</span>
                    </div>
                ))}
            </div>
        </div>
        {report && (
            <div className="bg-white/5 rounded-lg p-3 border border-white/10">
                 <div className="text-[10px] font-orbitron text-astra-blue tracking-widest mb-2 flex items-center gap-2">
                    <Search size={12} /> FORENSIC_ANALYSIS
                 </div>
                 <div className="prose prose-invert text-sm font-light text-gray-300">
                     <ReactMarkdown>{report}</ReactMarkdown>
                 </div>
            </div>
        )}
        {conclusion && (
            <div className={`rounded-xl border p-4 ${isDanger ? 'border-red-500/50 bg-red-950/30' : 'border-green-500/50 bg-green-950/30'}`}>
                <div className="text-[10px] font-orbitron text-white tracking-widest mb-2">VERDICT_SUMMARY</div>
                <div className="font-mono text-sm font-bold whitespace-pre-wrap text-gray-200">{conclusion}</div>
            </div>
        )}
    </div>
  );
};


export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [genMode, setGenMode] = useState<GenerationMode>('CHAT');
  const [astraMode, setAstraMode] = useState<AstraMode>('shield'); 
  const [attachment, setAttachment] = useState<Attachment | null>(null);
  const [featureMenuOpen, setFeatureMenuOpen] = useState(false);
  const [personalityMenuOpen, setPersonalityMenuOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [scanningImage, setScanningImage] = useState<string | null>(null);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [isInputFocused, setIsInputFocused] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [speakingMessageId, setSpeakingMessageId] = useState<string | null>(null);
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(DEFAULT_VOICE_SETTINGS);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isInitialized = useRef(false);
  const liveSessionRef = useRef<AstraLiveSession | null>(null);
  const personalityMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isInitialized.current) return;
    isInitialized.current = true;
    const savedHistory = localStorage.getItem('ASTRA_HISTORY');
    const savedAstraMode = localStorage.getItem('ASTRA_MODE') as AstraMode || 'shield';
    const savedGenMode = localStorage.getItem('ASTRA_GEN_MODE') as GenerationMode || 'CHAT';

    if (savedHistory) {
       try {
           const parsedMsgs = JSON.parse(savedHistory);
           setMessages(parsedMsgs);
           setAstraMode(savedAstraMode);
           setGenMode(savedGenMode);
           initializeChat(savedGenMode, savedAstraMode, getHistoryForGemini(parsedMsgs));
       } catch (e) { startFreshSession('shield', 'CHAT'); }
    } else { startFreshSession('shield', 'CHAT'); }
  }, []);

  useEffect(() => {
     if (isInitialized.current) {
        localStorage.setItem('ASTRA_HISTORY', JSON.stringify(messages));
        localStorage.setItem('ASTRA_MODE', astraMode);
        localStorage.setItem('ASTRA_GEN_MODE', genMode);
     }
  }, [messages, astraMode, genMode]);

  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const startFreshSession = (newAstraMode: AstraMode, newGenMode: GenerationMode) => {
      initializeChat(newGenMode, newAstraMode);
      let greeting = INITIAL_GREETING_SHIELD;
      if (newAstraMode === 'skull') greeting = INITIAL_GREETING_SKULL;
      if (newAstraMode === 'root') greeting = INITIAL_GREETING_ROOT;
      setMessages([{ id: 'init', role: Role.MODEL, text: greeting, timestamp: Date.now() }]);
  };

  const handleSend = async () => {
    if ((!input.trim() && !attachment) || isLoading) return;
    const userMsg: Message = { id: Date.now().toString(), role: Role.USER, text: input, image: attachment?.previewUrl, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const curAttach = attachment;
    setAttachment(null);
    setIsLoading(true);

    const modelMsgId = (Date.now() + 1).toString();
    const updateModelMsg = (text: string) => {
        setMessages(prev => {
            const exists = prev.find(m => m.id === modelMsgId);
            if (exists) return prev.map(m => m.id === modelMsgId ? { ...m, text } : m);
            return [...prev, { id: modelMsgId, role: Role.MODEL, text, timestamp: Date.now() }];
        });
    };

    try {
        if (genMode === 'IMAGE_EDIT') {
            updateModelMsg('>> RENDERING_VISUAL_DATA...');
            const img = await generateEditedImage(userMsg.text, curAttach?.base64, curAttach?.mimeType);
            if (img) setMessages(prev => prev.map(m => m.id === modelMsgId ? { ...m, text: ">> IMAGE_GENERATED.", image: img } : m));
            else updateModelMsg(">> ERROR: RENDER FAILED.");
        } else if (genMode === 'ASTRA_DETECTION' && curAttach) {
            setScanningImage(curAttach.previewUrl);
            const result = await runAstraDetection(curAttach, updateModelMsg);
            updateModelMsg(result);
        } else {
            let effMode = genMode;
            if (genMode === 'CHAT' && detectNewsIntent(userMsg.text)) effMode = 'WEB_INTEL';
            await sendMessageToGemini(userMsg.text, curAttach, effMode, astraMode, updateModelMsg, () => {}, getHistoryForGemini([...messages, userMsg]));
        }
    } catch (e) { updateModelMsg(">> SYSTEM_FAILURE: KERNEL_PANIC."); }
    setIsLoading(false);
    setScanningImage(null);
  };

  const features = [
      { id: 'CHAT', label: 'CORE SHELL', desc: 'Standard Intel', icon: Terminal },
      { id: 'DEEP_THINK', label: 'DEEP REASONING', desc: 'Auth-Mode Pentesting', icon: BrainCircuit },
      { id: 'WEB_INTEL', label: 'OSINT CORE', desc: 'Live Intel Extraction', icon: Globe },
      { id: 'ASTRA_CODER', label: 'EXPLOIT ARCHITECT', desc: 'Advanced Dev Tooling', icon: Code2 },
      { id: 'ASTRA_DETECTION', label: 'DEEP-SCAN', desc: 'Forensic Audit', icon: ScanEye },
  ];

  const getThemeClasses = () => {
      switch(astraMode) {
          case 'skull': return 'bg-[#1a0000] text-red-200';
          case 'root': return 'bg-black text-[#00FF41] font-terminal crt-scanlines';
          default: return 'bg-[#050505] text-white';
      }
  };

  return (
    <div className={`fixed inset-0 z-50 flex flex-col h-[100dvh] w-full overflow-hidden transition-all duration-700 ${getThemeClasses()}`}>
      {astraMode === 'root' && <MatrixRain />}

      <header className={`relative z-50 flex items-center justify-between p-4 border-b ${astraMode === 'root' ? 'border-[#00FF41]/30 bg-black/90' : 'border-white/10 bg-black/40 backdrop-blur-md'}`}>
          <div className="flex items-center gap-4">
              <button onClick={onBack} className="hover:scale-110 transition-transform">
                  <Logo className="w-10 h-10" isHackerMode={astraMode === 'root'} />
              </button>
              <div className="hidden sm:block">
                  <div className={`text-xs font-orbitron tracking-widest ${astraMode === 'root' ? 'text-red-500' : 'text-astra-blue'}`}>
                      {astraMode === 'root' ? 'ROOT_ACCESS_LEVEL: 0' : 'ASTRA_SENTINEL'}
                  </div>
                  <div className="text-[10px] opacity-40 font-mono">ENCRYPTION: AES-256-GCM</div>
              </div>
          </div>

          <button 
            onClick={() => setFeatureMenuOpen(!featureMenuOpen)}
            className={`px-6 py-2 rounded-full border flex items-center gap-3 transition-all ${astraMode === 'root' ? 'border-red-500 text-red-500 bg-red-950/20' : 'border-astra-blue/30 text-astra-blue bg-white/5'}`}
          >
              <Activity size={16} className="animate-pulse" />
              <span className="font-orbitron text-xs font-bold">{genMode}</span>
              <ChevronDown size={14} />
          </button>

          <div className="flex items-center gap-2">
              <button onClick={() => setMessages([])} className="p-2 hover:bg-white/10 rounded-lg text-gray-500"><Trash2 size={18} /></button>
          </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-10 space-y-6 scroll-smooth pb-32">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === Role.USER ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] relative ${
                msg.role === Role.USER 
                ? 'bg-[#111] border border-white/10 px-6 py-3 rounded-2xl rounded-tr-none text-gray-200' 
                : astraMode === 'root' 
                    ? 'font-terminal text-xl text-[#00FF41] animate-jitter' 
                    : 'text-gray-300'
            }`}>
                {msg.role === Role.MODEL && astraMode === 'root' && (
                    <div className="text-[10px] text-red-500 font-mono mb-2">[THREAD_ID: {msg.id.slice(-4)}] [AUTH: ROOT]</div>
                )}
                {msg.image && <img src={msg.image} className="max-w-md w-full rounded-lg mb-4 border border-white/10 shadow-2xl" />}
                <div className="prose prose-invert prose-green max-w-none">
                    {msg.text.includes('[ANOMALIES_DETECTED]') ? <ForensicResultDisplay text={msg.text} /> : <ReactMarkdown>{msg.text}</ReactMarkdown>}
                </div>
            </div>
          </div>
        ))}
        {isLoading && <div className="text-xs font-terminal text-[#00FF41] animate-pulse">>> FETCHING_DATA_STREAM...</div>}
        <div ref={messagesEndRef} />
      </main>

      <div className={`p-4 md:p-6 border-t ${astraMode === 'root' ? 'border-[#00FF41]/20 bg-black' : 'border-white/10 bg-[#050505]'}`}>
         <div className="max-w-5xl mx-auto flex items-end gap-3">
            <button 
                onClick={() => setAstraMode(astraMode === 'shield' ? 'root' : 'shield')} 
                className={`p-4 rounded-xl transition-all border ${astraMode === 'root' ? 'border-red-500 text-red-500 bg-red-950/20 shadow-[0_0_15px_rgba(255,0,0,0.3)]' : 'border-white/10 text-gray-400 hover:text-white'}`}
            >
                {astraMode === 'root' ? <Skull size={20} /> : <Shield size={20} />}
            </button>

            <div className={`flex-1 flex items-center p-3 rounded-xl border transition-all ${isInputFocused ? 'border-astra-blue/50 ring-1 ring-astra-blue/20' : 'border-white/5'}`}>
                {astraMode === 'root' && <span className="text-red-500 font-terminal mr-2">#root_shell:</span>}
                <textarea 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onFocus={() => setIsInputFocused(true)}
                    onBlur={() => setIsInputFocused(false)}
                    placeholder={astraMode === 'root' ? "ENTER_COMMAND..." : "Message ASTRA..."}
                    className="w-full bg-transparent outline-none resize-none text-sm font-light py-1"
                    rows={1}
                />
                <button onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-500 hover:text-white"><Paperclip size={18} /></button>
            </div>

            <button 
                onClick={handleSend}
                disabled={isLoading}
                className={`p-4 rounded-xl transition-all shadow-xl ${astraMode === 'root' ? 'bg-red-600 text-white' : 'bg-astra-blue text-black font-bold'}`}
            >
                <Send size={20} />
            </button>
         </div>
      </div>

      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
          if (e.target.files?.[0]) {
              const f = e.target.files[0];
              const r = new FileReader();
              r.onload = (ev) => setAttachment({ file: f, previewUrl: URL.createObjectURL(f), base64: (ev.target?.result as string).split(',')[1], mimeType: f.type });
              r.readAsDataURL(f);
          }
      }} />

      <AnimatePresence>
        {featureMenuOpen && (
            <motion.div initial={{ opacity: 0, y: 100 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 100 }} className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 p-6">
                <div className="max-w-md w-full bg-[#0a0a0a] border border-white/20 rounded-3xl p-6">
                    <div className="flex justify-between items-center mb-6">
                        <h2 className="font-orbitron font-bold text-astra-blue">PROTOCOLS</h2>
                        <button onClick={() => setFeatureMenuOpen(false)}><X /></button>
                    </div>
                    <div className="space-y-3">
                        {features.map(f => (
                            <button key={f.id} onClick={() => { setGenMode(f.id as GenerationMode); setFeatureMenuOpen(false); }} className={`w-full p-4 rounded-2xl flex items-center gap-4 text-left border ${genMode === f.id ? 'border-astra-blue bg-astra-blue/10' : 'border-white/5 hover:bg-white/5'}`}>
                                <f.icon className={genMode === f.id ? 'text-astra-blue' : 'text-gray-500'} />
                                <div>
                                    <div className="font-bold text-sm">{f.label}</div>
                                    <div className="text-[10px] text-gray-500">{f.desc}</div>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>
            </motion.div>
        )}
      </AnimatePresence>
      {scanningImage && <AstraScanner imageUrl={scanningImage} />}
    </div>
  );
};
